$content = $content.Replace('id="section-benefits" class="treatment-section" style="background: var(--neutral-surface);"', 'id="section-benefits" class="treatment-section dermaplaning-benefits-section" style="background: var(--neutral-surface);"')
$content = $content.Replace('<p>Discover what makes dermaplaning special</p>', '<p>Discover what makes dermaplaning special with visible improvements from your very first session.</p>')
